const UpdateVendSessionStateByOrderSlot = `-- name: UpdateVendSessionStateByOrderSlot :one
UPDATE vend_sessions
SET
    state = $3,
    failure_reason = $4,
    completed_at = CASE
        WHEN $3 IN ('success', 'failed') THEN now()
        ELSE completed_at
    END,
    started_at = CASE
        WHEN $3 = 'in_progress'
        AND started_at IS NULL THEN now()
        ELSE started_at
    END
WHERE
    order_id = $1
    AND slot_index = $2
RETURNING
    id,
    order_id,
    machine_id,
    slot_index,
    product_id,
    state,
    failure_reason,
    correlation_id,
    started_at,
    completed_at,
    final_command_attempt_id,
    created_at
`

type UpdateVendSessionStateByOrderSlotParams struct {
	OrderID       uuid.UUID
	SlotIndex     int32
	State         string
	FailureReason pgtype.Text
}

func (q *Queries) UpdateVendSessionStateByOrderSlot(ctx context.Context, arg UpdateVendSessionStateByOrderSlotParams) (VendSession, error) {
	row := q.db.QueryRow(ctx, UpdateVendSessionStateByOrderSlot,
		arg.OrderID,
		arg.SlotIndex,
		arg.State,
		arg.FailureReason,
	)
	var i VendSession
	err := row.Scan(
		&i.ID,
		&i.OrderID,
		&i.MachineID,
		&i.SlotIndex,
		&i.ProductID,
		&i.State,
		&i.FailureReason,
		&i.CorrelationID,
		&i.StartedAt,
		&i.CompletedAt,
		&i.FinalCommandAttemptID,
		&i.CreatedAt,
	)
	return i, err
}
